import json

def get_active_loan_id(payload):
    # กรณี payload เป็นรูปแบบที่อยู่ใน content.text
    if isinstance(payload, dict) and "content" in payload:
        # ดึงข้อความ JSON ที่ซ่อนอยู่ใน content.text
        for item in payload["content"]:
            if item.get("type") == "text" and "text" in item:
                try:
                    payload = json.loads(item["text"])
                except json.JSONDecodeError:
                    continue

    # ตอนนี้ payload ควรจะเป็น list หรือ dict ที่มี key "rows"
    rows = payload.get("rows") if isinstance(payload, dict) else payload

    if not rows:
        return None

    for row in rows:
        if row.get("status") == "ACTIVE":
            return row.get("loan_id")   # คืนค่า loan_id ของสัญญาแรกที่ ACTIVE

    return None   # ไม่พบสัญญาที่ ACTIVE

