ถ้าต้องการดึงค่าในโค้ด (เช่น Python) สามารถทำได้ดังนี้ — รองรับทั้งรูปแบบอาร์เรย์ธรรมดาและรูปแบบที่อยู่ภายใน `content.text`:

```python
import json

def get_customer_id(data):
    """
    ดึงค่า customer_id ของลูกค้าที่ชื่อเต็ม 'สมชาย ใจดี'
    รองรับสองโครงสร้าง:
    1. [{"customer_id":..., "name":..., ...}, ...]
    2. {"content": [{"type":"text","text":"{ \"rows\": [ {...} ] }"}]}
    """
    # ── 1️⃣ ตรวจสอบว่าข้อมูลเป็นอาร์เรย์หรือเป็น dict ──
    if isinstance(data, list):
        rows = data                                   # รูปแบบที่ 1
    elif isinstance(data, dict) and "content" in data:
        # รูปแบบที่ 2: ดึงข้อความ JSON จาก content.text
        txt = next(
            (item["text"] for item in data["content"]
             if item.get("type") == "text" and "text" in item),
            None
        )
        if txt is None:
            raise ValueError("ไม่พบข้อความ JSON ใน content")
        # แปลงสตริง JSON (ที่เป็น escaped string) ให้เป็น dict
        inner = json.loads(txt)                       # => {"rows": [ {...} ]}
        rows = inner.get("rows", [])
    else:
        raise TypeError("รูปแบบข้อมูลไม่รองรับ")

    # ── 2️⃣ ค้นหา customer_id ที่ชื่อเต็ม 'สมชาย ใจดี' ──
    for row in rows:
        if row.get("name") == "สมชาย ใจดี":
            return row.get("customer_id")

    # ไม่พบ
    return None


